import re
import boto3
from urllib.parse import urlparse
import ipaddress
import socket


def is_safe_endpoint(url: str, allowed_domains: list[str] | None = None) -> tuple[bool, str]:
    """
    Validate that the endpoint URL is safe to subscribe.
    Prevents SSRF by blocking internal/private IPs and restricting to allowed domains.
    """
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Invalid URL format"

    # Enforce HTTPS only
    if parsed.scheme != "https":
        return False, "Only HTTPS endpoints are allowed"

    if not parsed.hostname:
        return False, "URL must contain a valid hostname"

    hostname = parsed.hostname

    # Block IP-based URLs to prevent direct IP SSRF
    try:
        ip = ipaddress.ip_address(hostname)
        return False, "IP-based URLs are not allowed; use domain names"
    except ValueError:
        pass  # Not an IP, which is what we want

    # Check against allowed domains if provided
    if allowed_domains:
        domain_match = any(
            hostname == domain or hostname.endswith(f".{domain}")
            for domain in allowed_domains
        )
        if not domain_match:
            return False, f"Domain '{hostname}' is not in the allowed list: {allowed_domains}"

    # Resolve the hostname and check for private/internal IPs
    try:
        resolved_ips = socket.getaddrinfo(hostname, None)
        for entry in resolved_ips:
            ip = ipaddress.ip_address(entry[4][0])
            if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved:
                return False, f"Domain resolves to a private/internal IP address ({ip})"
    except socket.gaierror:
        return False, f"Could not resolve hostname: {hostname}"

    # Block common metadata endpoints
    blocked_patterns = [
        r"169\.254\.169\.254",
        r"metadata\.google\.internal",
        r"metadata\.internal",
    ]
    for pattern in blocked_patterns:
        if re.search(pattern, url, re.IGNORECASE):
            return False, "URL matches a blocked metadata endpoint pattern"

    return True, "OK"


class SNSSubscriptionManager:
    """Manages SNS subscriptions with input validation to prevent SSRF."""

    # Configure allowed domains for webhook endpoints
    ALLOWED_DOMAINS = [
        "example.com",
        "webhooks.yourcompany.com",
        # Add your trusted webhook domains here
    ]

    def __init__(self, topic_arn: str, region_name: str = "us-east-1"):
        self.topic_arn = topic_arn
        self.sns_client = boto3.client("sns", region_name=region_name)

    def subscribe(self, endpoint_url: str) -> dict:
        """Create an SNS subscription after validating the endpoint."""
        # Validate the endpoint
        is_safe, reason = is_safe_endpoint(endpoint_url, self.ALLOWED_DOMAINS)
        if not is_safe:
            raise ValueError(f"Endpoint rejected: {reason}")

        response = self.sns_client.subscribe(
            TopicArn=self.topic_arn,
            Protocol="https",
            Endpoint=endpoint_url,
            ReturnSubscriptionArn=True,
        )

        print(f"Subscription created: {response['SubscriptionArn']}")
        return response

    def list_subscriptions(self) -> list[dict]:
        """List all subscriptions for the topic."""
        response = self.sns_client.list_subscriptions_by_topic(TopicArn=self.topic_arn)
        return response.get("Subscriptions", [])

    def unsubscribe(self, subscription_arn: str) -> dict:
        """Remove a subscription."""
        response = self.sns_client.unsubscribe(SubscriptionArn=subscription_arn)
        print(f"Unsubscribed: {subscription_arn}")
        return response


def main():
    topic_arn = input("Enter SNS Topic ARN: ").strip()

    if not re.match(r"^arn:aws:sns:[a-z0-9-]+:\d{12}:.+$", topic_arn):
        print("Error: Invalid SNS Topic ARN format.")
        return

    manager = SNSSubscriptionManager(topic_arn)

    while True:
        print("\n--- SNS Subscription Manager ---")
        print("1. Add subscription")
        print("2. List subscriptions")
        print("3. Remove subscription")
        print("4. Exit")

        choice = input("Select an option: ").strip()

        if choice == "1":
            endpoint = input("Enter webhook HTTPS endpoint URL: ").strip()
            try:
                manager.subscribe(endpoint)
            except ValueError as e:
                print(f"Validation error: {e}")
